import{c as s,cG as i,cb as a,c8 as n,cf as l,cT as t,ce as e}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"08. 分支与跳转","description":"","frontmatter":{"title":"08. 分支与跳转","outline":"deep","layout":"doc","prev":{"text":"07. Load 与 Store 指令","link":"/lang/assembly/07_load_store"},"next":{"text":"09. 伪指令体系","link":"/lang/assembly/09_pseudo_instructions"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/08_branches_jumps.md","filePath":"lang/assembly/08_branches_jumps.md","lastUpdated":1780201301000}'),p={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"lang/assembly/08_branches_jumps.md"},[["render",function(s,h,k,d,r,c){return i(),a("div",null,[n("h1",p,[l(t(s.$frontmatter.title)+" ",1),h[0]||(h[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=e('<p>分支与跳转赋予 CPU &quot;选择&quot;的能力——根据条件改变执行路径。没有它们，程序就是一条直线，从第一条指令走到最后一条。RISC-V 的分支跳转体系只包含 6 条分支指令 + 2 条跳转指令，却足以表达从 <code>if</code> 到 <code>switch</code> 的所有高级控制流。</p><h2 id="条件分支指令-b-type" tabindex="-1">条件分支指令（B-type） <a class="header-anchor" href="#条件分支指令-b-type" aria-label="Permalink to “条件分支指令（B-type）”">​</a></h2><p>B-type 格式用于条件分支，opcode = <code>1100011</code>。6 条分支指令覆盖了所有比较模式：</p><table tabindex="0"><thead><tr><th>指令</th><th>funct3</th><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><code>beq rs1, rs2, offset</code></td><td>000</td><td>rs1 == rs2</td><td>Branch if Equal</td></tr><tr><td><code>bne rs1, rs2, offset</code></td><td>001</td><td>rs1 != rs2</td><td>Branch if Not Equal</td></tr><tr><td><code>blt rs1, rs2, offset</code></td><td>100</td><td>rs1 &lt; rs2（有符号）</td><td>Branch if Less Than</td></tr><tr><td><code>bge rs1, rs2, offset</code></td><td>101</td><td>rs1 &gt;= rs2（有符号）</td><td>Branch if Greater or Equal</td></tr><tr><td><code>bltu rs1, rs2, offset</code></td><td>110</td><td>rs1 &lt; rs2（无符号）</td><td>Branch if Less Than Unsigned</td></tr><tr><td><code>bgeu rs1, rs2, offset</code></td><td>111</td><td>rs1 &gt;= rs2（无符号）</td><td>Branch if Greater or Equal Unsigned</td></tr></tbody></table><h3 id="b-type-指令格式" tabindex="-1">B-type 指令格式 <a class="header-anchor" href="#b-type-指令格式" aria-label="Permalink to “B-type 指令格式”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>B-type: ┌───────────┬───────┬───────┬─────┬──────────┬─────────┐</span></span>\n<span class="line"><span>        │imm[12|10:5]│ rs2  │ rs1  │funct3│imm[4:1|11]│ opcode  │</span></span>\n<span class="line"><span>        └─────7──────┴───5───┴───5───┴──3───┴────5─────┴────7────┘</span></span></code></pre></div><p>B-type 的立即数编码是六种格式中最不直观的。立即数被拆散到 bit 31（imm[12]）、bit 30:25（imm[10:5]）、bit 11:8（imm[4:1]）、bit 7（imm[11]）。且 bit 0 被省略——因为 RISC-V 指令总是 2 字节对齐（C 扩展的存在使得对齐粒度是 2 字节而非 4 字节），目标地址的最低位始终为 0，无需编码。</p><p><strong>立即数的重组</strong>（硬件做的事）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>imm = {imm[12], imm[10:5], imm[4:1], imm[11], 0}</span></span></code></pre></div><p>相当于 13 位偏移量（bit 12:1）左移 1 位。实际跳转范围：PC ± 4KB。</p><h3 id="为什么分支范围只有-±4kb" tabindex="-1">为什么分支范围只有 ±4KB？ <a class="header-anchor" href="#为什么分支范围只有-±4kb" aria-label="Permalink to “为什么分支范围只有 ±4KB？”">​</a></h3><p>4KB 听起来很小，但绝大多数分支目标都在几十条指令之内（if/else 两端、循环体、局部跳转）。长距离跳转使用 <code>jal</code>（±1MB）或 <code>jalr</code>（任意 64 位地址）。将分支范围压缩到 12 位立即数能节省 B-type 指令的 bits，保持指令定长 4 字节。如果编译器遇到了超出 4KB 的条件分支，会自动将 <code>beq</code> 翻转后接 <code>jal</code>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 长距离条件分支的编译器展开：</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># if (a0 == a1) goto far_label;  → 超出 ±4KB</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bne  a0, a1, skip    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 翻转条件：不等则跳过 jal</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    jal  x0, far_label   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 相等则无条件跳转（±1MB 范围）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">skip:</span></span></code></pre></div><h3 id="分支与-pc-相对寻址" tabindex="-1">分支与 PC 相对寻址 <a class="header-anchor" href="#分支与-pc-相对寻址" aria-label="Permalink to “分支与 PC 相对寻址”">​</a></h3><p>B-type 的分支目标是 <strong>PC 相对</strong>的：<code>target = PC + sext(imm)</code>。由于立即数的 LSB（bit 0）被省略，编码中的偏移量在拼接后自动左移 1 位。在汇编时，汇编器自动计算 <code>label - PC</code> 的差值，写入立即数位域。程序员只需写标签名字，不需要手动算偏移。</p><h2 id="无条件跳转" tabindex="-1">无条件跳转 <a class="header-anchor" href="#无条件跳转" aria-label="Permalink to “无条件跳转”">​</a></h2><h3 id="jal-j-type" tabindex="-1">JAL（J-type） <a class="header-anchor" href="#jal-j-type" aria-label="Permalink to “JAL（J-type）”">​</a></h3><p><code>jal rd, offset</code>（Jump and Link）：将 PC+4 写入 rd（返回地址），然后跳转到 PC + sext(offset)。opcode = <code>1101111</code>。</p><p><strong>J-type 格式</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>J-type: ┌──────────────────────────┬───────┬─────────┐</span></span>\n<span class="line"><span>        │  imm[20|10:1|11|19:12]  │  rd   │ opcode  │</span></span>\n<span class="line"><span>        └───────────20─────────────┴───5───┴────7────┘</span></span></code></pre></div><p>20 位立即数（同样省略 bit 0）×2 = 21 位偏移量，跳转范围 ±1MB。和 B-type 一样，立即数由汇编器从标签距离自动计算。</p><p><strong>关键模式</strong>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 函数调用</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jal ra, func_label    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ra = PC+4（返回地址）, PC = func_label</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等效伪指令: call func_label</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 无条件跳转（不保存返回地址）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jal x0, label         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # x0 = 丢弃返回地址 → 纯跳转</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等效伪指令: j label</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 调用者代码模式</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    jal  ra, my_func      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 调用 my_func</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">back:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # ra 指向这里</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 函数返回后继续执行...</span></span></code></pre></div><h3 id="jalr-i-type-但独立-opcode" tabindex="-1">JALR（I-type，但独立 opcode） <a class="header-anchor" href="#jalr-i-type-但独立-opcode" aria-label="Permalink to “JALR（I-type，但独立 opcode）”">​</a></h3><p><code>jalr rd, rs1, offset</code>（Jump and Link Register）：rd = PC+4，PC = (rs1 + sext(offset)) &amp; ~1。opcode = <code>1100111</code>，funct3 = 000。</p><p>JALR 使用 I-type 格式（12 位立即数 + rs1），但拥有独立的 opcode（不与立即数算术指令共享 0010011）。目标地址的最低位置零（<code>&amp; ~1</code>）确保 2 字节对齐。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 函数返回</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jalr x0, ra, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # x0 = 丢弃返回地址, PC = ra → 等价于 ret 伪指令</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 间接调用（函数指针）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jalr ra, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 调用 t0 指向的函数（虚函数表的核心）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 远跳转：任意 64 位地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">auipc t0, hi20        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = PC + 高位立即数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jalr x0, t0, lo12    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # PC = t0 + lo12 → 跳转到绝对地址</span></span></code></pre></div><p>jalr 的返回地址写入 rd = x0 表示&quot;跳转但不记返回地址&quot;——等价于无条件跳转。写入 ra 则是标准的函数调用。</p><h2 id="控制流翻译" tabindex="-1">控制流翻译 <a class="header-anchor" href="#控制流翻译" aria-label="Permalink to “控制流翻译”">​</a></h2><p>RISC-V 的分支跳转体系只有 8 条指令。一切高级控制流——if-else、for、while、do-while、switch——最终都翻译为分支 + 跳转的组合。理解这些翻译模式就能从反汇编中还原控制流结构。</p><h3 id="if-then-无-else-块" tabindex="-1">if-then（无 else 块） <a class="header-anchor" href="#if-then-无-else-块" aria-label="Permalink to “if-then（无 else 块）”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: if (a &gt;= 0) a = a + 1;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bgez a0, then_body    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 &gt;= 0 则进入 then 块（伪指令 bgez ≈ bge x, x0, label）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    after_if          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 条件不成立，跳过 then 块</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then_body:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi a0, a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">after_if:</span></span></code></pre></div><p>关键：<strong>对条件取反来决定&quot;跳过&quot;</strong>。<code>if (cond)</code> 翻译为：若条件不成立则跳过 then 块；若成立则执行 then 块后继续。</p><h3 id="if-then-else" tabindex="-1">if-then-else <a class="header-anchor" href="#if-then-else" aria-label="Permalink to “if-then-else”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: if (a &lt; b) max = b; else max = a;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    blt  a0, a1, then_case   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 &lt; a1 → then</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    # </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 分支（隐含：a0 &gt;= a1）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, a0              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # max = a</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    end_if</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then_case:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, a1              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # max = b</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">end_if:</span></span></code></pre></div><p>编译器常见的优化：当 then/else 都很短时，直接用条件传送（基于 <code>slt</code> 的掩码技巧）替代分支，避免分支预测失败。</p><h3 id="while-循环" tabindex="-1">while 循环 <a class="header-anchor" href="#while-循环" aria-label="Permalink to “while 循环”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: while (i &lt; n) { sum += a[i]; i++; }</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # i = 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t1, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # sum = 0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">while_cond:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bge  t0, a1, while_done </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # i &gt;= n → 退出</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    slli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t2 = i * 8</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, a0, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = &amp;a[i]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld   t3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t2)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = a[i]</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t3         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # sum += a[i]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # i++</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    while_cond</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">while_done:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # t1 = sum</span></span></code></pre></div><p>模式：<strong>前置条件检查 + 条件不满足跳末尾 + body + 无条件跳回条件检查</strong>。</p><h3 id="for-循环" tabindex="-1">for 循环 <a class="header-anchor" href="#for-循环" aria-label="Permalink to “for 循环”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: for (i = 0; i &lt; n; i++) sum += a[i];</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # i = 0（init）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beqz a1, for_done       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # n = 0 的空循环快速退出</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t1, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # sum = 0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">for_cond:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bge  t0, a1, for_done   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 条件检查（前置）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    slli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, a0, t2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld   t3, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t2)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t3         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # body</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # inc（后置）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    for_cond</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">for_done:</span></span></code></pre></div><p>for 循环和 while 循环在汇编层没有区别——都是 init → 条件检查 → body → 递增 → 跳回条件检查。编译器对 for 和 while 生成相同的汇编代码。</p><h3 id="do-while-循环" tabindex="-1">do-while 循环 <a class="header-anchor" href="#do-while-循环" aria-label="Permalink to “do-while 循环”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: do { x = f(x); } while (x != 0);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, a0</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">do_body:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   a0, t0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    jal  ra, f              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # x = f(x)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   t0, a0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez t0, do_body        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # x != 0 → 继续</span></span></code></pre></div><p>do-while 是唯一<strong>不需要前置条件检查</strong>的循环——进入时无条件执行 body，退出条件在末尾判断。在汇编层通常比 while 少一条分支指令。</p><h3 id="switch-case-跳转表" tabindex="-1">switch / case：跳转表 <a class="header-anchor" href="#switch-case-跳转表" aria-label="Permalink to “switch / case：跳转表”">​</a></h3><p>switch 语句在 case 密集且连续时，编译器用跳转表替换 if-else 链：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C: switch (x) { case 0: ...; case 1: ...; case 2: ...; default: ...; }</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 假设 x 在 t0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # case 最大值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bltu t1, t0, default_case  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # x &gt; 2 → default</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la   t3, jumptable</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    slli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # t2 = x * 4（每个跳转表项 4 字节）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t3, t2           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = &amp;jumptable[x]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lw   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t2)            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 加载跳转偏移</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t3, t2           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = jumptable_base + offset</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    jalr x0, t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # PC = t2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">default_case:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 处理默认情况</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .rodata</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jumptable:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">word</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> case0 - jumptable</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">word</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> case1 - jumptable</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">word</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> case2 - jumptable</span></span></code></pre></div><p>跳转表的本质是 PC 相对偏移数组：用 <code>jalr</code> 的基址+偏移能力，将 switch 表达式的值作为数组索引，在跳转表（<code>.word</code> 数组）中查找偏移量后跳转。时间复杂度 O(1)——而 if-else 链在最坏情况下需要检查每个 case。</p><h2 id="无-flags-寄存器-risc-v-的分支哲学" tabindex="-1">无 Flags 寄存器：RISC-V 的分支哲学 <a class="header-anchor" href="#无-flags-寄存器-risc-v-的分支哲学" aria-label="Permalink to “无 Flags 寄存器：RISC-V 的分支哲学”">​</a></h2><p>这是 RISC-V 与 x86/ARM 最根本的设计分歧之一。值得深入理解其代价和收益。</p><h3 id="x86-的-flags-方式" tabindex="-1">x86 的 FLAGS 方式 <a class="header-anchor" href="#x86-的-flags-方式" aria-label="Permalink to “x86 的 FLAGS 方式”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CMP rax, rbx      # 比较：设置 FLAGS（ZF, CF, SF, OF）</span></span>\n<span class="line"><span>Jxx  label        # 分支：根据 FLAGS 各位决定是否跳转</span></span></code></pre></div><p>两步操作：先比较（设置隐式状态），再分支（读取隐式状态）。FLAGS 寄存器是隐藏的全局变量——所有 ALU 指令都可能修改 FLAGS，指令重排时必须&quot;小心&quot;不破坏 FLAGS 依赖链。</p><h3 id="risc-v-的融合方式" tabindex="-1">RISC-V 的融合方式 <a class="header-anchor" href="#risc-v-的融合方式" aria-label="Permalink to “RISC-V 的融合方式”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>blt a0, a1, label   # 一条指令：比较并分支</span></span></code></pre></div><p>RISC-V 把比较和分支<strong>合并为一条指令</strong>。没有中间状态，没有隐式 FLAGS 寄存器，每条分支指令同时完成比较和跳转。代价：</p><p><strong>缺点</strong>：RISC-V 缺少纯&quot;大于&quot;和&quot;大于等于&quot;的分支。<code>if (a &gt; b)</code> 必须写成 <code>blt b, a, label</code>（交换操作数）。多了些心智负担。</p><p><strong>优点</strong>：</p><ol><li><strong>无隐式状态</strong>：ALU 指令执行后不改变任何全局状态。指令重排（乱序执行）的自由度更高——不需要维护 FLAGS 的假依赖</li><li><strong>流水线更简单</strong>：分支在 Execute 阶段同时完成比较和地址计算，不需要单独的&quot;条件码写回&quot;阶段</li><li><strong>节省状态位</strong>：FLAGS 需要 5 条以上额外状态线贯穿整个流水线。RISC-V 彻底消除了这种设计</li><li><strong>密集编码</strong>：6 条分支指令覆盖所有比较模式——而 x86 需要 CMP + Jcc 两步，且 Jcc 和 CMP 之间需要保留条件码不被改写的&quot;气泡&quot;</li></ol><p>ARM 的更早期版本有&quot;条件执行&quot;（每条指令的 bit 31:28 是条件码，可根据 FLAGS 决定是否执行），ARMv8 放弃了这种做法（代价：每个指令码 4 bits 被条件码占用，浪费编码空间）。</p><p>RISC-V 的设计师显然是吸取了这些历史教训——不设条件码，分支自包含，指令编码规整。</p><h3 id="flags-缺失的补偿-set-before-branch" tabindex="-1">FLAGS 缺失的补偿：set-before-branch <a class="header-anchor" href="#flags-缺失的补偿-set-before-branch" aria-label="Permalink to “FLAGS 缺失的补偿：set-before-branch”">​</a></h3><p>需要&quot;先计算比较结果，再后续分支&quot;时，RISC-V 用 <code>slt</code> + <code>bne</code> 显式实现：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在不同基本块中使用比较结果</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slt  t0, a0, a1     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = (a0 &lt; a1)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ... 其他代码（不破坏 t0）...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bnez t0, label      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 根据之前保存的比较结果跳转</span></span></code></pre></div><p>这条指令序列有 FLAGS 范式的等价功能性——但 t0 是显式的通用寄存器，编译器可以自由调度它。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>B-type 的 6 条分支指令（beq/bne/blt/bge/bltu/bgeu）+ PC 相对寻址 ±4KB 覆盖所有条件转移</li><li>JAL（J-type, ±1MB）和 JALR（I-type, 任意地址）提供无条件和间接跳转——函数调用、返回、跳转表的基础</li><li>所有高级控制流（if/else/while/for/switch）可翻译为 branch + jump 的组合——do-while 是唯一不需要前置检查的循环</li><li>RISC-V 无 FLAGS 寄存器——比较与分支融合为一条指令，消除隐式状态、简化流水线、提高指令重排自由度</li><li>无&quot;大于&quot;/&quot;大于等于&quot;分支指令——交换操作数用 blt/bge，多一步心智操作但节省了硬件和编码空间</li></ul>',68))])}]]);export{h as __pageData,k as default};
